import bisect
from typing import List

class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        len_a = len(a)
        len_b = len(b)
        A = []
        for i in range(len(s) - len_a + 1):
            if s[i:i+len_a] == a:
                A.append(i)
        B = []
        for i in range(len(s) - len_b + 1):
            if s[i:i+len_b] == b:
                B.append(i)
        result = []
        for i in A:
            target = i - k
            idx = bisect.bisect_left(B, target)
            if idx < len(B) and B[idx] <= (i + k):
                result.append(i)
        return result
